import express from "express";
import AdminController from "./admin.controller.js";
import AdminService from "./admin.service.js";
import AdminRepository from "./admin.repository.js";
import checkAuth from "../../shared/middleware/auth.js";
import { requireAdmin } from "../../shared/middleware/auth.js";
import tryCatch from "../../shared/utils/tryCatch.utils.js";
const adminRepository = new AdminRepository();
const adminService = new AdminService(adminRepository);
const adminController = new AdminController(adminService);
const adminRouter = express.Router();
adminRouter.get("/health", tryCatch(adminController.getSystemHealth));
adminRouter.use(checkAuth, requireAdmin);
adminRouter.get("/stats", tryCatch(adminController.getStats));
adminRouter.get("/users", tryCatch(adminController.getAllUsers));
adminRouter.get("/users/:id", tryCatch(adminController.getUserById));
adminRouter.patch("/users/:id/role", tryCatch(adminController.updateUserRole));
adminRouter.patch("/users/:id/status", tryCatch(adminController.updateUserStatus));
export default adminRouter;
